// // This module implements a combinational circuit that selects the output Y based on the inputs A1, A2, and B1_N.
// - If A1 and A2 are both high, Y should be low.
// - If A1 is high and A2 is low, Y should be high.
// - If A1 is low and A2 is high, Y should be high.
// - If A1 and A2 are both low, Y should be low if and only if B1_N is high.
module combinational_circuit (
    input A1,
    input A2,
    input B1_N,
    output reg Y
);

always @* begin
    if (A1 && A2) begin
        Y = 1;
    end else if (A1 && !A2) begin
        Y = 0;
    end else if (!A1 && A2) begin
        Y = 0;
    end else begin
        Y = B1_N;
    end
end

endmodule

